import{WebSocketManager}from'./websocket-manager.js';import{DataProcessor}from'./data-processor.js';import{SystemStatusDashboard}from'./dashboard/systemstatus.js';import{NetworkDashboard}from'./dashboard/network.js';import{DiskDashboard}from'./dashboard/disk.js';import{DiskIODashboard}from'./dashboard/diskio.js';import{HistoryDashboard}from'./dashboard/history.js';const DASHBOARD_CLASSES={'systemstatus':SystemStatusDashboard,'network':NetworkDashboard,'disk':DiskDashboard,'diskio':DiskIODashboard,'history':HistoryDashboard};export class Dashboard{constructor(sysname,topic){console.log(`[Dashboard] Initializing dashboard for ${sysname}, topic: ${topic}`);this.sysname=sysname;this.topic=topic||'systemstatus';this.wsManager=new WebSocketManager(sysname,this.topic);this.dataProcessor=new DataProcessor();const DashboardClass=DASHBOARD_CLASSES[this.topic];if(!DashboardClass){console.warn(`[Dashboard] Unknown topic: ${this.topic}, using SystemStatusDashboard`);this.uiUpdater=new SystemStatusDashboard(this.dataProcessor);}else{this.uiUpdater=new DashboardClass(this.dataProcessor);}
this.uiUpdater.registerElements();if(typeof this.uiUpdater.attachWebSocketManager==='function'){this.uiUpdater.attachWebSocketManager(this.wsManager,this.sysname,this.topic);}
this.setupWebSocketHandlers();if(this.topic!=='history'){this.wsManager.connect();}else{console.log('[Dashboard] History page: Skipping WebSocket connection (using HTTP API)');}}
setupWebSocketHandlers(){console.log('[Dashboard] Setting up WebSocket handlers');this.wsManager.on('connected',()=>{console.log(`[Dashboard] WebSocket connected to ${this.sysname}/${this.topic}`);this.uiUpdater.hideError();});this.wsManager.on('disconnected',()=>{console.log('[Dashboard] WebSocket disconnected');});this.wsManager.on('error',(error)=>{console.error('[Dashboard] WebSocket error:',error);this.uiUpdater.showError('Connection error. Attempting to reconnect...',()=>{console.log('[Dashboard] Retry button clicked, reconnecting...');this.wsManager.connect();});});this.wsManager.on('reconnect_failed',()=>{console.error('[Dashboard] Reconnection failed');this.uiUpdater.showError('Server is unreachable. Please check your connection.',()=>{console.log('[Dashboard] Retry button clicked, reconnecting...');this.wsManager.connect();});});this.wsManager.on('message',(message)=>{this.handleMessage(message);});}
handleMessage(message){console.log('[Dashboard] Handling message:',message.type,'topic:',message.topic,'expected:',this.topic);console.log('[Dashboard] Message data:',message.data);if(message.type==='data'&&message.topic===this.topic){try{console.log(`[Dashboard] Processing ${this.topic} data...`);this.dataProcessor.process(this.topic,message.data).then(processedData=>{console.log(`[Dashboard] Processed data:`,processedData);if(processedData){console.log(`[Dashboard] Updating UI for topic: ${this.topic}`);this.uiUpdater.update(processedData);this.uiUpdater.hideError();}else{console.warn('[Dashboard] Failed to process data');this.uiUpdater.showWarning('Failed to process data');}}).catch(error=>{console.error('[Dashboard] Error processing message:',error);this.uiUpdater.showWarning('Error processing data: '+error.message);});}catch(error){console.error('[Dashboard] Error handling message:',error);this.uiUpdater.showWarning('Error processing data: '+error.message);}}}
destroy(){console.log('[Dashboard] Destroying dashboard');this.wsManager.disconnect();try{if(this.uiUpdater&&this.uiUpdater.charts&&this.uiUpdater.charts.dataManager&&typeof this.uiUpdater.charts.dataManager.destroy==='function'){this.uiUpdater.charts.dataManager.destroy();console.log('[Dashboard] ChartDataManager destroyed');}}catch(e){console.warn('[Dashboard] Error during ChartDataManager destroy',e);}}}
document.addEventListener('DOMContentLoaded',()=>{console.log('[Dashboard] DOM loaded, initializing dashboard');let sysname=document.body.dataset.sysname;let topic=document.body.dataset.topic;if(!sysname||!topic){const pathParts=window.location.pathname.split('/').filter(p=>p);const dashboardIndex=pathParts.indexOf('dashboard');if(dashboardIndex!==-1&&dashboardIndex+1<pathParts.length){sysname=sysname||pathParts[dashboardIndex+1];if(dashboardIndex+2<pathParts.length){topic=topic||pathParts[dashboardIndex+2];}}
sysname=sysname||'default';topic=topic||'systemstatus';}
console.log(`[Dashboard] Initializing: sysname=${sysname}, topic=${topic}`);const serverNameElement=document.getElementById('server-name');if(serverNameElement){serverNameElement.textContent=sysname;}
requestAnimationFrame(()=>{window.dashboard=new Dashboard(sysname,topic);});window.addEventListener('beforeunload',()=>{console.log('[Dashboard] Page unloading, cleaning up...');if(window.dashboard){window.dashboard.destroy();}});});